"use client";
import { Star, StarHalf, Trash2, ShoppingCart, ArrowRight } from "lucide-react";
import Link from "next/link";
import { useEffect, useState, useMemo } from "react";
import toast from "react-hot-toast";
import { Button } from "../ui/button";
import { getUserIdFromToken } from "@/utils/helpers";
import { motion, AnimatePresence } from "framer-motion";
import { Skeleton } from "../ui/skeleton";
import router from "next/router";
import { createRazorpayOrder, verifyPayment } from "@/features/api/course-purchase/route";

declare global {
  interface Window {
    Razorpay: any;
  }
}

interface RatingStarsProps {
  rating: number;
}

const RatingStars: React.FC<RatingStarsProps> = ({ rating }) => {
  const totalStars = 5;
  const fullStars = Math.floor(rating);
  const hasHalfStar = rating - fullStars >= 0.5;
  const emptyStars = totalStars - fullStars - (hasHalfStar ? 1 : 0);

  return (
    <div className="flex items-center">
      {Array.from({ length: fullStars }).map((_, index) => (
        <Star key={`full-${index}`} className="h-4 w-4 text-yellow-400 fill-current" />
      ))}
      {hasHalfStar && <StarHalf key="half" className="h-4 w-4 text-yellow-400 fill-current" />}
      {Array.from({ length: emptyStars }).map((_, index) => (
        <Star key={`empty-${index}`} className="h-4 w-4 text-gray-300 dark:text-gray-600" />
      ))}
    </div>
  );
};

interface Course {
  _id: string;
  courseTitle: string;
  courseThumbnail: string;
  coursePrice: number;
  courseMRP?: number;
  creator: { name: string } | string;
}

interface CartItemType {
  courseId: Course;
}

export default function Cart() {
  const [cart, setCart] = useState<CartItemType[]>([]);
  const [courseRatings, setCourseRatings] = useState<{ [key: string]: any }>({});
  const [isLoading, setIsLoading] = useState(true);
  const userId = getUserIdFromToken();
  const [quickPurchase, setQuickPurchase] = useState<any>(null);

  useEffect(() => {
    // Check for quick purchase data in session storage
    const data = sessionStorage.getItem('quickPurchase');
    if (data) {
      setQuickPurchase(JSON.parse(data));
    }
  }, []);

  const fetchCart = async () => {
    setIsLoading(true);
    try {
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/cart/${userId}/getUserCart`);
      if (!res.ok) throw new Error("Failed to fetch cart");
      const data = await res.json();
      setCart(data);
    } catch (error) {
      toast.error("Failed to load cart.");
      setCart([]);
    } finally {
      setIsLoading(false);
    }
  };

  const removeFromCart = async (courseId: string) => {
    try {
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/cart/${courseId}/remove-from-cart`, {
        method: "DELETE",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ userId }),
      });
      if (!res.ok) throw new Error("Failed to remove course");
      setCart(cart.filter((item) => item.courseId._id !== courseId));
      toast.success("Removed a Course from cart!");
    } catch (error) {
      toast.error("Failed to remove course.");
    }
  };

  useEffect(() => {
    if (userId) fetchCart();
  }, [userId]);

  useEffect(() => {
    if (cart.length === 0) return;
    const fetchRatings = async () => {
      const ratings: { [key: string]: any } = {};
      for (const item of cart) {
        try {
          const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL}/ratings/${item.courseId._id}`);
          if (res.ok) {
            const data = await res.json();
            ratings[item.courseId._id] = data;
          }
        } catch (error) {
          console.error(`Error fetching rating for course ${item.courseId._id}:`, error);
        }
      }
      setCourseRatings(ratings);
    };
    fetchRatings();
  }, [cart]);

  const { totalPrice, totalMRP, totalDiscount } = useMemo(() => {
    const totalPrice = cart.reduce((acc, item) => acc + item.courseId.coursePrice, 0);
    const totalMRP = cart.reduce((acc, item) => acc + (item.courseId.courseMRP || item.courseId.coursePrice), 0);
    const totalDiscount = totalMRP - totalPrice;
    return { totalPrice, totalMRP, totalDiscount };
  }, [cart]);

  const handleProceedToCheckout = async () => {
    if (!userId) {
      router.push("/login");
      return;
    }

    if (cart.length === 0) {
      toast.error("Your cart is empty.");
      return;
    }

    const courseId = cart[0].courseId._id;

    try {
      const { order } = await createRazorpayOrder(courseId, userId);

      const options = {
        key: process.env.NEXT_PUBLIC_RAZORPAY_KEY_ID,
        amount: order.amount,
        currency: order.currency,
        name: "Mr English",
        description: "Course Purchase",
        order_id: order.id,
        handler: async function (response: { razorpay_payment_id: any; razorpay_order_id: any; razorpay_signature: any; }) {
          const data = await verifyPayment({
            razorpay_payment_id: response.razorpay_payment_id,
            razorpay_order_id: response.razorpay_order_id,
            razorpay_signature: response.razorpay_signature,
          });
          if (data?.success) {
            toast.success("Payment successful!");
            router.push(`/course/course-progress/${courseId}`);
          } else {
            toast.error("Payment verification failed.");
          }
        },
        prefill: {
          name: "",
          email: "",
          contact: "",
        },
        notes: {},
        theme: { color: "#3399cc" },
      };

      const rzp = new window.Razorpay(options);
      rzp.open();
    } catch (error) {
      toast.error("Failed to initiate payment. Please try again.");
      console.error(error);
    }
  };

  if (isLoading) {
    return <CartSkeleton />;
  }

  return (
    <div className="container mx-auto px-4 sm:px-6 lg:px-8 py-6 sm:py-8 lg:py-12">
      <motion.div
        initial={{ opacity: 0, y: -20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
        className="text-center mb-6 sm:mb-8 lg:mb-12"
      >
        <h1 className="text-2xl sm:text-3xl lg:text-4xl xl:text-5xl font-extrabold tracking-tight">
          Your Shopping Cart
        </h1>
        <p className="mt-3 sm:mt-4 max-w-2xl mx-auto text-base sm:text-lg text-muted-foreground">
          You have {cart.length} course(s) in your cart.
        </p>
      </motion.div>

      {quickPurchase ? (
        <div className="flex flex-col lg:flex-row gap-6 sm:gap-8 lg:gap-10">
          <div className="w-full lg:w-2/3">
            <div className="space-y-3 sm:space-y-4">
              <motion.div
                layout
                initial={{ opacity: 0, x: -50 }}
                animate={{ opacity: 1, x: 0 }}
                className="flex flex-col gap-3 sm:gap-4 border rounded-lg p-3 sm:p-4 bg-card dark:bg-gray-800/50 shadow-sm"
              >
                <div className="flex-1">
                  <div className="flex flex-col sm:flex-row justify-between items-start gap-3">
                    <div className="flex-1">
                      <h3 className="font-semibold text-base sm:text-lg">{quickPurchase.product}</h3>
                      <div className="mt-2 text-xs sm:text-sm text-muted-foreground space-y-1">
                        <p><strong>Name:</strong> {quickPurchase.name}</p>
                        <p><strong>Email:</strong> {quickPurchase.email}</p>
                        <p><strong>WhatsApp:</strong> {quickPurchase.whatsapp}</p>
                        {quickPurchase.message && (
                          <p><strong>Message:</strong> {quickPurchase.message}</p>
                        )}
                      </div>
                    </div>
                    <div className="text-right sm:text-left">
                      <div className="text-lg sm:text-xl font-bold">₹{quickPurchase.price}</div>
                    </div>
                  </div>
                </div>
              </motion.div>
            </div>
          </div>
          <div className="w-full lg:w-1/3 lg:sticky lg:top-24 self-start">
            <div className="p-4 sm:p-6 bg-card dark:bg-gray-800/50 rounded-lg shadow-sm border">
              <h2 className="text-xl sm:text-2xl font-bold mb-3 sm:mb-4">Order Summary</h2>
              <div className="space-y-2">
                <div className="flex justify-between text-lg sm:text-xl font-bold">
                  <span>Total:</span>
                  <span>₹{quickPurchase.price}</span>
                </div>
              </div>
              <Button 
                size="lg" 
                className="w-full mt-4 sm:mt-6 text-sm sm:text-base" 
                onClick={async () => {
                  try {
                    const response = await fetch('/api/enroll-live', {
                      method: 'POST',
                      headers: {
                        'Content-Type': 'application/json',
                      },
                      body: JSON.stringify(quickPurchase),
                    });
                    
                    if (response.ok) {
                      if (!userId) {
                            router.push("/login");
                            return;
                          }
                          try {
                            const courseId = quickPurchase.courseId;
                            const { order } = await createRazorpayOrder(courseId, userId);
                      
                            const options = {
                              key: process.env.NEXT_PUBLIC_RAZORPAY_KEY_ID,
                              amount: order.amount,
                              currency: order.currency,
                              name: "Mr English",
                              description: "Course Purchase",
                              order_id: order.id,
                              handler: async function (response: { razorpay_payment_id: any; razorpay_order_id: any; razorpay_signature: any; }) {
                                const data = await verifyPayment({
                                  razorpay_payment_id: response.razorpay_payment_id,
                                  razorpay_order_id: response.razorpay_order_id,
                                  razorpay_signature: response.razorpay_signature,
                                });
                                if (data?.success) {
                                  toast.success("Payment successful!");
                                  router.push(`/course/course-progress/${quickPurchase.courseId}`);
                                } else {
                                  toast.error("Payment verification failed.");
                                  toast.error("Payment verification failed.");
                                }
                              },
                              prefill: {
                                name: "Your Name",
                                email: "your.email@example.com",
                                contact: "9999999999",
                              },
                              notes: {
                                address: "Your Address",
                              },
                              theme: {
                                color: "#3399cc",
                              },
                            };
                      
                            const rzp = new window.Razorpay(options);
                            rzp.open();
                          } catch (error) {
                            toast.error(`Error during checkout: ${error}`);
                          }
                      toast.success("Proceeding to payment gateway!");
                      // TODO: Integrate with your payment gateway here
                      sessionStorage.removeItem('quickPurchase');
                    } else {
                      throw new Error('Failed to process enrollment');
                    }
                  } catch (error) {
                    toast.error("Failed to process payment. Please try again.");
                  }
                }}
              >
                Proceed to Payment <ArrowRight className="ml-2 h-5 w-5" />
              </Button>
            </div>
          </div>
        </div>
      ) : cart.length === 0 ? (
        <EmptyCart />
      ) : (
        <div className="flex flex-col lg:flex-row gap-6 sm:gap-8 lg:gap-10">
          <div className="w-full lg:w-2/3">
            <div className="space-y-3 sm:space-y-4">
              <AnimatePresence>
                {cart.map((item) => (
                  <CartItem
                    key={item.courseId._id}
                    item={item}
                    rating={courseRatings[item.courseId._id]}
                    onRemove={removeFromCart}
                  />
                ))}
              </AnimatePresence>
            </div>
          </div>
          <div className="w-full lg:w-1/3 lg:sticky top-24 self-start">
            <CheckoutSummary
              totalPrice={totalPrice}
              totalMRP={totalMRP}
              totalDiscount={totalDiscount}
              onProceed={handleProceedToCheckout}
            />
          </div>
        </div>
      )}
    </div>
  );
}

interface CartItemProps {
  item: CartItemType;
  rating: any;
  onRemove: (courseId: string) => void;
}

const CartItem: React.FC<CartItemProps> = ({ item, rating, onRemove }) => {
  const discountPercentage = useMemo(() => {
    if (item.courseId.courseMRP && item.courseId.coursePrice) {
      return Math.round(
        ((item.courseId.courseMRP - item.courseId.coursePrice) / item.courseId.courseMRP) * 100
      );
    }
    return 0;
  }, [item]);

  return (
    <motion.div
      layout
      initial={{ opacity: 0, x: -50 }}
      animate={{ opacity: 1, x: 0 }}
      exit={{ opacity: 0, x: 50, transition: { duration: 0.3 } }}
      className="flex flex-col sm:flex-row gap-4 border rounded-lg p-4 bg-card dark:bg-gray-800/50 shadow-sm"
    >
      <div className="w-full sm:w-48 h-32 bg-secondary rounded-lg overflow-hidden relative">
        <img
          src={item.courseId.courseThumbnail}
          alt={item.courseId.courseTitle}
          className="w-full h-full object-cover"
        />
        {discountPercentage > 0 && (
          <div className="absolute top-0 right-0 bg-destructive text-destructive-foreground px-2 py-1 text-xs font-bold">
            {discountPercentage}% OFF
          </div>
        )}
      </div>
      <div className="flex-1">
        <div className="flex justify-between items-start">
          <div>
            <Link href={`/course/course-detail/${item.courseId._id}`}>
              <h3 className="font-semibold text-lg hover:underline">{item.courseId.courseTitle}</h3>
            </Link>
            <div className="flex items-center gap-2 mt-1">
              {rating ? (
                <>
                  <RatingStars rating={rating.average} />
                  <span className="text-sm text-muted-foreground">({rating.count} reviews)</span>
                </>
              ) : (
                <span className="text-sm text-muted-foreground">No ratings yet</span>
              )}
            </div>
          </div>
          <div className="text-right">
            <div className="text-lg font-bold">₹{item.courseId.coursePrice}</div>
            {(item.courseId.courseMRP || 0) > item.courseId.coursePrice && (
              <div className="text-sm text-muted-foreground line-through">₹{item.courseId.courseMRP}</div>
            )}
          </div>
        </div>
        <div className="flex justify-end mt-4">
          <Button variant="ghost" size="sm" onClick={() => onRemove(item.courseId._id)}>
            <Trash2 className="h-4 w-4 mr-2" />
            Remove
          </Button>
        </div>
      </div>
    </motion.div>
  );
};

interface CheckoutSummaryProps {
  totalPrice: number;
  totalMRP: number;
  totalDiscount: number;
  onProceed: () => void | Promise<void>;
}

const CheckoutSummary: React.FC<CheckoutSummaryProps> = ({ totalPrice, totalMRP, totalDiscount, onProceed }) => (
  <div className="p-6 bg-card dark:bg-gray-800/50 rounded-lg shadow-sm border">
    <h2 className="text-2xl font-bold mb-4">Order Summary</h2>
    <div className="space-y-2">
      <div className="flex justify-between">
      </div>
      <div className="flex justify-between text-green-600 dark:text-green-400">
      </div>
      <hr className="my-2" />
      <div className="flex justify-between text-xl font-bold">
        <span>Total:</span>
        <span>₹{totalPrice}</span>
      </div>
    </div>
    <Button size="lg" className="w-full mt-6" onClick={onProceed}>
      Proceed to Checkout <ArrowRight className="ml-2 h-5 w-5" />
    </Button>
  </div>
);

const EmptyCart = () => (
  <div className="text-center py-16">
    <ShoppingCart className="mx-auto h-24 w-24 text-muted-foreground" />
    <h2 className="mt-6 text-2xl font-semibold">Your cart is empty</h2>
    <p className="mt-2 text-muted-foreground">
      Looks like you haven't added anything to your cart yet.
    </p>
    <div className="mt-6">
      <Link href="/courses">
        <Button size="lg">
          <ArrowRight className="mr-2 h-5 w-5" />
          Explore Courses
        </Button>
      </Link>
    </div>
  </div>
);

const CartSkeleton = () => (
  <div className="container mx-auto px-4 sm:px-6 lg:px-8 py-12">
    <div className="text-center mb-12">
      <Skeleton className="h-12 w-3/4 mx-auto" />
      <Skeleton className="h-6 w-1/2 mx-auto mt-4" />
    </div>
    <div className="flex flex-col lg:flex-row gap-10">
      <div className="w-full lg:w-2/3 space-y-4">
        <Skeleton className="h-32 w-full rounded-lg" />
        <Skeleton className="h-32 w-full rounded-lg" />
        <Skeleton className="h-32 w-full rounded-lg" />
      </div>
      <div className="w-full lg:w-1/3">
        <Skeleton className="h-64 w-full rounded-lg" />
      </div>
    </div>
  </div>
);
